import{_ as e,o as r,c as o,ag as s}from"./chunks/framework.ePeAWSvT.js";const a="/assets/monitor-error-logs.BvIsC_LU.png",p=JSON.parse('{"title":"Error Logs","description":"","frontmatter":{},"headers":[],"relativePath":"guide/monitor-error-logs.md","filePath":"guide/monitor-error-logs.md"}'),n={name:"guide/monitor-error-logs.md"};function i(l,t,d,g,c,h){return r(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="error-logs" tabindex="-1">Error Logs <a class="header-anchor" href="#error-logs" aria-label="Permalink to &quot;Error Logs&quot;">​</a></h1><p>The Error Logs page surfaces processing errors from your integrations. Investigate failures, view error details, and take corrective action.</p><p><img src="'+a+'" alt="Error Logs Page"></p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Error Search</strong> — Filter errors by endpoint, date range, and entity type</li><li><strong>Error Details</strong> — View full error messages, stack traces, and related log items</li><li><strong>Troubleshooting</strong> — Navigate from errors to the related message metadata</li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>Error data can be found via several features, such as <strong>Monitor</strong> &gt; <strong>Messages</strong> and <strong>Monitor</strong> &gt; <strong>Error Logs</strong>, as well as the <strong>Actions</strong> &gt; <strong>View Details</strong> for each instance (row) within these features. For those with advanced skills, error messages can also be found within the code view.</p></div><h2 id="view-and-manage-error-logs" tabindex="-1">View and Manage Error Logs <a class="header-anchor" href="#view-and-manage-error-logs" aria-label="Permalink to &quot;View and Manage Error Logs&quot;">​</a></h2><ol><li>Select <strong>Monitor</strong> &gt; <strong>Error Logs</strong>.</li><li>Then, use the table below to determine the next steps.</li></ol><table tabindex="0"><thead><tr><th>To</th><th>Do this</th></tr></thead><tbody><tr><td><strong>View the data</strong></td><td>All transaction data will be displayed in the table.</td></tr><tr><td><strong>Refresh the data</strong></td><td>Select <strong>Reload</strong>.</td></tr><tr><td><strong>View a specific time range</strong></td><td>Select <strong>Set Range</strong>. Select a pre-formulated <strong>timeframe</strong> (e.g. Last Hour) or select <strong>Custom</strong> to apply a specific date and time. Select <strong>Apply</strong>.</td></tr><tr><td><strong>Re-run the message</strong></td><td>Select <strong>Actions</strong> &gt; <strong>Re-Run Message</strong> in the appropriate row.</td></tr><tr><td><strong>View message details</strong></td><td>Select <strong>Actions</strong> &gt; <strong>View Details</strong> in the appropriate row. A Message Details window will appear; select a <strong>tab</strong> to view additional information: <strong>Message</strong> (code view), <strong>Receipts</strong> (subscribers and error log data), <strong>Outputs</strong> (file download links if applicable), and <strong>Re-Run History</strong> (audit of previous re-runs). Select <strong>Cancel</strong> to close and return to the previous screen.</td></tr><tr><td><strong>View record history</strong></td><td>Select <strong>Actions</strong> &gt; <strong>View Record History</strong> in the appropriate row. The record history for that error will open in a new browser tab, displaying all messages associated with that record, including all activity and errors with timestamps. From this screen, you can select <strong>Actions</strong> &gt; <strong>Re-Run Message</strong> or <strong>Actions</strong> &gt; <strong>View Details</strong>.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The <strong>Re-Run Message</strong> option should be used only if you understand the error and believe it has already been fixed in the triggering system.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>It is advised to view the message details, which provides an opportunity to analyze the error details and formulate a fix; however, as needed, you can also select to <strong>Re-Run</strong> the message from the details view.</p><p>Viewing record history is a good way to find out if the error has already been resolved. For example, if an error happened when syncing a sales order at 8 PM, but was successful when it ran again at 9 PM, both messages would appear in the history.</p></div><h2 id="error-log-reference-table" tabindex="-1">Error Log Reference Table <a class="header-anchor" href="#error-log-reference-table" aria-label="Permalink to &quot;Error Log Reference Table&quot;">​</a></h2><p>Use the table below to better understand the data available in the Error Logs.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Hover over and select the <strong>filter</strong> icon or <strong>sort</strong> arrow in any column header to narrow your search. The filters will vary based on that column&#39;s data. You can apply filters to one or multiple columns, as needed.</p></div><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>Endpoint Name</strong></td><td>The system that triggered the message.</td></tr><tr><td><strong>Identifier</strong></td><td>The unique identifier for that record in the system that triggered the message.</td></tr><tr><td><strong>Error Text</strong></td><td>Error message details.</td></tr><tr><td><strong>Total Errors</strong></td><td>The number of error messages within the set date range.</td></tr><tr><td><strong>Message Date</strong></td><td>The date and time stamp that message occurred.</td></tr><tr><td><strong>Actions</strong></td><td>Enables users to Re-Run Message, View Details, and View Record History.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Example</p><p>If you find that the Identifier with the Message Search error shows 3186, and the Endpoint Name shows it was generated by NetSuite, then you can go to your NetSuite application to view record 3186 to gather additional information.</p></div><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./monitor-messages.html">Messages</a> — Inspect individual integration messages</li><li><a href="./monitor-dashboard.html">Monitor Dashboard</a> — View platform health at a glance</li><li><a href="./monitor-alerts.html">Alerts</a> — Configure automated error notifications</li></ul>',18)])])}const m=e(n,[["render",i]]);export{p as __pageData,m as default};
